previewCss:
.darma-loader-darma-custom-153 {
  color: var(--loader-color, #9333ea);
width: 45px;
height: 26px;
--c:no-repeat linear-gradient(135deg,currentColor,var(--loader-secondary-color, #d8b4fe));
background:
var(--c) 0 100%,
var(--c) 50% 100%,
var(--c) 100% 100%;
background-size:8px calc(100% - 4px);
position: relative;
}
.darma-loader-darma-custom-153:before {
content: "";
position: absolute;
width: 8px;
height: 8px;
border-radius: 50%;
background: currentColor;
left: 0;
top: 0;
animation:
darma-loader-darma-custom-153-l3-1 1.5s linear infinite alternate,
darma-loader-darma-custom-153-l3-2 0.75s cubic-bezier(0,200,.8,200) infinite;
}
@keyframes darma-loader-darma-custom-153-l3-1 {
100% {left:calc(100% - 8px)}
}
@keyframes darma-loader-darma-custom-153-l3-2 {
100% {top:-0.1px}
}

